const ValueSection = () => {
  const getExpiry = () => {
    const stored = sessionStorage.getItem('eb_offer_expiry');
    if (stored) return parseInt(stored);
    const expiry = Date.now() + 1 * 60 * 60 * 1000;
    sessionStorage.setItem('eb_offer_expiry', String(expiry));
    return expiry;
  };

  const calcTimeLeft = () => {
    const diff = Math.max(0, getExpiry() - Date.now());
    const hrs = Math.floor(diff / 3600000);
    const min = Math.floor((diff % 3600000) / 60000);
    const sec = Math.floor((diff % 60000) / 1000);
    return {
      hrs: hrs.toString().padStart(2, '0'),
      min: min.toString().padStart(2, '0'),
      sec: sec.toString().padStart(2, '0'),
    };
  };

  const [timeLeft, setTimeLeft] = useState(calcTimeLeft);

  useEffect(() => {
    const timer = setInterval(() => setTimeLeft(calcTimeLeft()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <section className="px-6 py-12 flex flex-col items-center relative overflow-hidden">
      <div className="absolute -top-24 -right-24 w-64 h-64 bg-primary/10 blur-[100px] rounded-full"></div>

      {/* Hero copy for cold push traffic */}
      <div className="text-center mb-8 max-w-sm">
        <h2 className="text-2xl font-black uppercase tracking-tighter mb-3 leading-tight">
          South Africa's <span className="text-primary italic">Fastest Growing</span> Online Betting Site
        </h2>
        <p className="text-on-surface-variant text-sm leading-relaxed">
          New to Easybet? You're in the right place. We're giving new players a <strong className="text-on-surface">R50 no-deposit bonus</strong> just for signing up — no strings attached. Bet on soccer, rugby, horse racing, casino and more.
        </p>
      </div>

      {/* Trust badges */}
      <div className="flex flex-wrap justify-center gap-2 mb-8">
        {[
          { icon: '🛡️', label: 'WCGRB Licensed' },
          { icon: '📶', label: 'Data Free' },
          { icon: '💳', label: 'Multiple Deposits' },
          { icon: '⭐', label: '4.3 Star Rated' },
        ].map((badge) => (
          <div key={badge.label} className="bg-surface-container-highest px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider text-on-surface/70 border border-outline-variant/20 flex items-center gap-1.5">
            <span>{badge.icon}</span> {badge.label}
          </div>
        ))}
      </div>

      {/* Bonus value */}
      <div className="text-center mb-8">
        <h3 className="text-xs uppercase tracking-[0.3em] text-on-surface-variant mb-2">Total Welcome Value</h3>
        <div className="relative inline-block">
          <span className="text-7xl font-black leading-none text-primary italic tracking-tighter">R1,500</span>
          <div className="absolute -bottom-2 right-0 bg-secondary text-on-secondary px-3 py-1 font-black text-xs uppercase italic transform translate-y-1/2">MATCH BONUS</div>
        </div>
      </div>

      {/* Countdown */}
      <p className="text-xs uppercase tracking-widest text-on-surface-variant mb-3">This offer expires in</p>
      <div className="flex gap-4 mb-10">
        {Object.entries(timeLeft).map(([unit, val]) => (
          <div key={unit} className="flex flex-col items-center">
            <div className="bg-surface-container-high w-14 h-14 rounded-lg flex items-center justify-center border border-outline-variant/20">
              <span className="text-2xl font-black text-primary">{val}</span>
            </div>
            <span className="text-[10px] mt-2 uppercase font-bold opacity-40">{unit.toUpperCase()}</span>
          </div>
        ))}
      </div>

      {/* Social proof */}
      <div className="glass-panel rounded-lg p-5 w-full max-w-sm border border-outline-variant/10 text-center mb-6">
        <div className="flex justify-center gap-1 mb-2">
          {[1,2,3,4].map(i => <span key={i} className="text-primary text-lg">★</span>)}
          <span className="text-primary/50 text-lg">★</span>
        </div>
        <p className="text-sm font-bold text-on-surface mb-1">"Easy to use, fast payouts"</p>
        <p className="text-xs text-on-surface-variant">Rated 4.3/5 by over 1,600 South African players on the app store</p>
      </div>

      {/* Second CTA */}
      <motion.div whileTap={{ scale: 0.95 }} className="w-full max-w-sm">
        <a href={TRACKING_LINK} target="_blank" rel="noopener noreferrer"
          className="block w-full bg-primary text-on-primary font-black py-5 rounded-lg text-lg uppercase tracking-wider text-center shadow-[0_10px_30px_rgba(255,214,0,0.25)]">
          Claim My Welcome Bonus →
        </a>
      </motion.div>
      <p className="text-[10px] text-on-surface-variant mt-3 uppercase tracking-wider">No deposit required to get started</p>
    </section>
  );
};

